SELECT DISTINCT u.user_id
FROM tb_user u
WHERE u.is_active = 1
  AND u.user_id != #{excludeUserId}
  AND (
    (
        #{deptId} IS NOT NULL AND u.dept_id = #{deptId}
        AND u.user_id IN (SELECT ur.user_id FROM tb_user_role ur WHERE ur.role = 'DEPT_MANAGER')
    )
    OR u.user_id IN (
        SELECT up.user_id FROM tb_user_permission up
        JOIN tb_permission p ON p.perm_id = up.perm_id
        WHERE p.perm_code = 'PASSWORD.APPROVE'
    )
  )
